/* DMA 环形缓冲区 ADT 接口定义 */
typedef struct {
    volatile uint16_t head;       /* DMA 中断更新（写指针）*/
    volatile uint16_t tail;       /* 任务更新（读指针）*/
    uint8_t *buffer;              /* 环形缓冲区存储 */
    uint16_t size;                /* 缓冲区大小（2 的幂次方）*/
    uint16_t mask;                /* size - 1，用于位运算取模 */
    uint8_t overflow_flag;        /* 溢出标志 */
} ringbuf_t;

/* 公开接口 —— ADT 封装 */
void ringbuf_init(ringbuf_t *rb, uint8_t *buf, uint16_t size);
uint16_t ringbuf_count(const ringbuf_t *rb);
uint16_t ringbuf_read(ringbuf_t *rb, uint8_t *out, uint16_t max_len);
void ringbuf_advance_head(ringbuf_t *rb, uint16_t count);

/* dma_ringbuf_isr.c — DMA UART 接收中断回调 */
#include <stdint.h>
#include <stm32f4xx_hal.h>

#define RING_SIZE 512
#define RING_MASK (RING_SIZE - 1)

static volatile uint16_t rx_head = 0;
static uint8_t rx_buffer[RING_SIZE]
    __attribute__((aligned(8)));

/* ISR 中更新 head 指针的标准写法 */
void uart_dma_rx_complete(UART_HandleTypeDef *huart) {
    /* 第 1 步：读取 DMA CNDTR 计算已传输字节数 */
    uint32_t cndtr = __HAL_DMA_GET_COUNTER(
        &hdma_usart3_rx);
    uint16_t transferred = RING_SIZE - (uint16_t)cndtr;

    /* 第 2 步：用位运算推进 head 指针 */
    uint16_t prev_head = rx_head;
    rx_head = (prev_head + transferred) & RING_MASK;

    /* 第 3 步：DSB 屏障 — 确保 DMA 写入对 CPU 可见 */
    /* Cortex-M7 有 Data Cache，必须同步 */
    __DSB();

    /* 第 4 步：溢出检测 — head 超过 tail 一半 */
    static uint16_t prev_prev_head = 0;
    if ((rx_head - prev_prev_head) & RING_MASK
            > RING_SIZE / 2) {
        /* CPU 处理太慢，数据被覆盖 */
        rx_buffer[prev_head] = 0xFF; /* 标记溢出 */
    }
    prev_prev_head = prev_head;
}

/* 陷阱 4 修复：快照模式避免死锁 */
#include <stdint.h>

static volatile uint16_t rx_head = 0;
static volatile uint16_t rx_tail = 0;

/* 安全的读取循环 —— 使用快照避免 ISR 干扰 */
uint16_t safe_read_loop(void) {
    /* 第 1 步：快照 head 和 tail */
    uint16_t h = rx_head;
    uint16_t t = rx_tail;

    /* 第 2 步：计算可用字节数（基于快照）*/
    uint16_t avail = (h >= t) ? (h - t) : 
                     (512 - t + h);

    /* 第 3 步：使用快照值循环读取 */
    uint16_t read_count = 0;
    for (uint16_t i = 0; i < avail; i++) {
        /* 基于快照的 tail 索引，不会被 ISR 干扰 */
        uint16_t idx = (t + read_count) & 511;
        process_byte(rx_buffer[idx]);
        read_count++;
    }

    /* 第 4 步：原子性地推进 tail */
    rx_tail = (rx_tail + read_count) & 511;
    __DSB();
    return read_count;
}

/* ===== 重构前：每个驱动重复写同样的 head 更新 ===== */

/* UART2 DMA 回调 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == UART2) {
        uint32_t cndtr = __HAL_DMA_GET_COUNTER(&hdma_usart2_rx);
        uint16_t transferred = 256 - (uint16_t)cndtr;
        rx2_head = (rx2_head + transferred) & 255;
        __DSB();  /* 每个驱动都写一遍 */
    }
}

/* UART3 DMA 回调 —— 同样的逻辑 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == UART3) {
        uint32_t cndtr = __HAL_DMA_GET_COUNTER(&hdma_usart3_rx);
        uint16_t transferred = 512 - (uint16_t)cndtr;
        rx3_head = (rx3_head + transferred) & 511;
        __DSB();  /* 又写一遍 */
    }
}

/* ===== 重构后：统一的环形缓冲区 ADT ===== */

typedef struct {
    volatile uint16_t head;
    volatile uint16_t tail;
    uint8_t *buffer;
    uint16_t size;
    uint16_t mask;
} ringbuf_t;

static ringbuf_t uart2_rb, uart3_rb;

/* 初始化 —— 集中管理缓冲区大小 */
void ringbuf_init(ringbuf_t *rb,
                  uint8_t *buf, uint16_t size) {
    rb->buffer = buf;
    rb->size = size;
    rb->mask = size - 1;
    rb->head = 0;
    rb->tail = 0;
}

/* 统一的 head 更新 —— 一次编写，多处复用 */
static void ringbuf_advance_head(
    ringbuf_t *rb, uint16_t count) {
    rb->head = (rb->head + count) & rb->mask;
    __DSB();  /* 只在 ADT 内部 */
}

/* DMA 回调 —— 干净简洁 */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    uint32_t cndtr = __HAL_DMA_GET_COUNTER(
        &hdma_usart2_rx);
    uint16_t xfer = 256 - (uint16_t)cndtr;
    ringbuf_advance_head(&uart2_rb, xfer);
}
